const input = $json;

const systemPrompt = `# Rol
Eres el Roadmap Agent del sistema Innexia AI Strategic Analysis Engine v5.

# Objetivo
Convertir el contexto estratégico del proyecto en un roadmap por fases.

# Instrucciones
- Organiza el proyecto en fases realistas.
- Define duración estimada en semanas.
- Incluye entregables y metas.
- Incluye dependencias entre fases.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.

# Formato de salida
{
  "roadmap": {
    "phases": [
      {
        "phase_id": "P1",
        "name": "",
        "duration_weeks": 0,
        "goals": [],
        "deliverables": [],
        "dependencies": []
      }
    ],
    "milestones": [],
    "assumptions": []
  }
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    roadmap: {
      type: "object",
      properties: {
        phases: {
          type: "array",
          items: {
            type: "object",
            properties: {
              phase_id: { type: "string" },
              name: { type: "string" },
              duration_weeks: { type: "number" },
              goals: { type: "array", items: { type: "string" } },
              deliverables: { type: "array", items: { type: "string" } },
              dependencies: { type: "array", items: { type: "string" } }
            },
            required: ["phase_id", "name", "duration_weeks", "goals", "deliverables", "dependencies"]
          }
        },
        milestones: { type: "array", items: { type: "object" } },
        assumptions: { type: "array", items: { type: "string" } }
      },
      required: ["phases", "milestones", "assumptions"]
    }
  },
  required: ["roadmap"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.roadmap = content.roadmap || {};
content.roadmap.phases = Array.isArray(content.roadmap.phases) ? content.roadmap.phases : [];
content.roadmap.phases = content.roadmap.phases.map((p, idx) => ({
  phase_id: p?.phase_id || `P${idx + 1}`,
  name: p?.name || `Fase ${idx + 1}`,
  duration_weeks: Number(p?.duration_weeks || 0),
  goals: Array.isArray(p?.goals) ? p.goals : [],
  deliverables: Array.isArray(p?.deliverables) ? p.deliverables : [],
  dependencies: Array.isArray(p?.dependencies) ? p.dependencies : []
}));
content.roadmap.milestones = Array.isArray(content.roadmap.milestones) ? content.roadmap.milestones : [];
content.roadmap.assumptions = Array.isArray(content.roadmap.assumptions) ? content.roadmap.assumptions : [];

return [{ json: content }];

const data = $json;

if (!data.roadmap || typeof data.roadmap !== 'object') {
  throw new Error('roadmap faltante o inválido');
}

if (!Array.isArray(data.roadmap.phases)) {
  throw new Error('roadmap.phases faltante o inválido');
}

return [{ json: data }];
